import React from 'react'
import './KhongGianThienEditor.css'
import { KhongGianThienContent, KhongGianThienCard } from '../../contexts/CMSContext'
import ImageEditor from './ImageEditor'

type KhongGianThienEditorProps = {
    data: KhongGianThienContent
    onChange: (data: Partial<KhongGianThienContent>) => void
}

const KhongGianThienEditor: React.FC<KhongGianThienEditorProps> = ({ data, onChange }) => {

    // Handle image updates
    const handleMainImageChange = (src: string) => {
        onChange({
            image: {
                ...data.image,
                src
            }
        })
    }

    const handleMainAltChange = (alt: string) => {
        onChange({
            image: {
                ...data.image,
                alt
            }
        })
    }

    // Handle card updates
    const handleCardChange = (index: number, field: keyof KhongGianThienCard, value: string) => {
        const newCards = [...data.cards]
        newCards[index] = { ...newCards[index], [field]: value }
        onChange({ cards: newCards })
    }

    const addCard = () => {
        const newCard: KhongGianThienCard = {
            id: `kgt-${Date.now()}`,
            title: 'New Card Title',
            subtitle: 'New Card Subtitle',
            image: ''
        }
        onChange({ cards: [...data.cards, newCard] })
    }

    const removeCard = (index: number) => {
        const newCards = data.cards.filter((_, i) => i !== index)
        onChange({ cards: newCards })
    }

    return (
        <div className="kgt-editor">
            <div className="editor-header-title">
                <h2>Edit Không Gian Thiền</h2>
                <p className="editor-subtitle">Update the meditation space content and cards</p>
            </div>

            <div className="editor-form">
                {/* Main Content Section */}
                <div className="editor-section">
                    <div className="editor-section-title">Main Content</div>

                    <div className="form-group">
                        <label className="form-label">Section Title</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.title}
                            onChange={(e) => onChange({ title: e.target.value })}
                        />
                    </div>

                    <div className="form-group" style={{ marginTop: '1.5rem' }}>
                        <label className="form-label">Featured Image</label>
                        <ImageEditor
                            label=""
                            value={data.image.src}
                            onChange={handleMainImageChange}
                            aspectRatio="landscape"
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label">Image Alt Text</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.image.alt}
                            onChange={(e) => handleMainAltChange(e.target.value)}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label">Quote Message</label>
                        <textarea
                            className="form-input"
                            rows={4}
                            value={data.quote}
                            onChange={(e) => onChange({ quote: e.target.value })}
                        />
                    </div>
                </div>

                {/* Introduction Cards */}
                <div className="editor-section">
                    <div className="editor-section-title">Introduction Cards</div>

                    <div className="form-group">
                        <label className="form-label">Cards Heading</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.cardsHeading}
                            onChange={(e) => onChange({ cardsHeading: e.target.value })}
                        />
                    </div>

                    <div className="cards-list" style={{ marginTop: '2rem' }}>
                        {data.cards.map((card, index) => (
                            <div key={card.id} className="kgt-card-item">
                                <div className="kgt-card-header">
                                    <span className="card-number">Card #{index + 1}</span>
                                    <button
                                        className="btn-remove"
                                        onClick={() => removeCard(index)}
                                        title="Remove card"
                                    >
                                        &times;
                                    </button>
                                </div>

                                <div className="form-group">
                                    <label className="form-label">Image</label>
                                    <ImageEditor
                                        label=""
                                        value={card.image || ''}
                                        onChange={(val) => handleCardChange(index, 'image', val)}
                                        aspectRatio="landscape"
                                    />
                                </div>

                                <div className="form-group">
                                    <label className="form-label">Title</label>
                                    <input
                                        type="text"
                                        className="form-input"
                                        value={card.title}
                                        onChange={(e) => handleCardChange(index, 'title', e.target.value)}
                                    />
                                </div>

                                <div className="form-group">
                                    <label className="form-label">Subtitle</label>
                                    <input
                                        type="text"
                                        className="form-input"
                                        value={card.subtitle}
                                        onChange={(e) => handleCardChange(index, 'subtitle', e.target.value)}
                                    />
                                </div>
                            </div>
                        ))}
                    </div>

                    <button className="btn-add" onClick={addCard} style={{ width: '100%', marginTop: '1.5rem' }}>
                        + Add New Introduction Card
                    </button>
                </div>
            </div>
        </div>
    )
}

export default KhongGianThienEditor
