import { useState, useEffect } from 'react';
import { Form, FormField } from '../components/ppm/cms/form-builder/FormBuilderTypes';

const STORAGE_KEY = 'sbu_cms_builder_forms';

export const useFormData = () => {
    const [forms, setForms] = useState<Form[]>([]);
    const [loading, setLoading] = useState(true);

    // Load forms from localStorage on mount
    useEffect(() => {
        const savedForms = localStorage.getItem(STORAGE_KEY);
        if (savedForms) {
            try {
                setForms(JSON.parse(savedForms));
            } catch (e) {
                console.error("Failed to parse saved forms", e);
                setForms([]);
            }
        }
        setLoading(false);
    }, []);

    // Save forms to localStorage whenever they change
    const saveToStorage = (updatedForms: Form[]) => {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedForms));
        setForms(updatedForms);
    };

    const createForm = (title: string, fields: FormField[] = []): Form => {
        const newForm: Form = {
            id: `form_${Date.now()}`,
            title: title || 'Untitled Form',
            fields: fields
        };
        const updated = [...forms, newForm];
        saveToStorage(updated);
        return newForm;
    };

    const updateForm = (formId: string, updates: Partial<Form>) => {
        const updated = forms.map(f => f.id === formId ? { ...f, ...updates } : f);
        saveToStorage(updated);
    };

    const deleteForm = (formId: string) => {
        const updated = forms.filter(f => f.id !== formId);
        saveToStorage(updated);
    };

    const renameForm = (formId: string, newTitle: string) => {
        updateForm(formId, { title: newTitle });
    };

    const addField = (formId: string, field: FormField) => {
        const currentForm = forms.find(f => f.id === formId);
        if (currentForm) {
            const updatedFields = [...currentForm.fields, field];
            updateForm(formId, { fields: updatedFields });
        }
    };

    const removeField = (formId: string, fieldId: string) => {
        const currentForm = forms.find(f => f.id === formId);
        if (currentForm) {
            const updatedFields = currentForm.fields.filter(f => f.id !== fieldId);
            updateForm(formId, { fields: updatedFields });
        }
    };

    return {
        forms,
        loading,
        createForm,
        updateForm,
        deleteForm,
        renameForm,
        addField,
        removeField
    };
};
