import React from 'react'
import './ChuongTrinhCaoDangEditor.css'
import { ChuongTrinhCaoDangContent } from '../../contexts/CMSContext'
import ImageEditor from './ImageEditor'

type ChuongTrinhCaoDangEditorProps = {
    data: ChuongTrinhCaoDangContent
    onChange: (data: Partial<ChuongTrinhCaoDangContent>) => void
}

const ChuongTrinhCaoDangEditor: React.FC<ChuongTrinhCaoDangEditorProps> = ({ data, onChange }) => {

    const updateScheduleItem = (index: number, value: string) => {
        const newSchedule = [...data.meta.schedule]
        newSchedule[index] = value
        onChange({
            meta: {
                ...data.meta,
                schedule: newSchedule
            }
        })
    }

    const addScheduleItem = () => {
        onChange({
            meta: {
                ...data.meta,
                schedule: [...data.meta.schedule, 'New schedule item']
            }
        })
    }

    const removeScheduleItem = (index: number) => {
        if (!window.confirm('Delete this schedule?')) return
        const newSchedule = data.meta.schedule.filter((_, i) => i !== index)
        onChange({
            meta: {
                ...data.meta,
                schedule: newSchedule
            }
        })
    }

    const updateCurriculumItem = (side: 'left' | 'right', index: number, value: string) => {
        const newItems = [...data.curriculum[side]]
        newItems[index] = value
        onChange({
            curriculum: {
                ...data.curriculum,
                [side]: newItems
            }
        })
    }

    const addCurriculumItem = (side: 'left' | 'right') => {
        const newItems = [...data.curriculum[side], 'New curriculum item']
        onChange({
            curriculum: {
                ...data.curriculum,
                [side]: newItems
            }
        })
    }

    const removeCurriculumItem = (side: 'left' | 'right', index: number) => {
        const newItems = data.curriculum[side].filter((_, i) => i !== index)
        onChange({
            curriculum: {
                ...data.curriculum,
                [side]: newItems
            }
        })
    }

    return (
        <div className="chuong-trinh-cao-dang-editor">
            <div className="editor-header-title">
                <h2>Edit Chương Trình Cao Đẳng</h2>
                <p className="editor-subtitle">Manage program details and curriculum</p>
            </div>

            <div className="editor-form">
                <div className="form-section">
                    <div className="form-group">
                        <label className="form-label">Program Title</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.title}
                            onChange={(e) => onChange({ title: e.target.value })}
                        />
                    </div>

                    <ImageEditor
                        label="Program Image"
                        value={data.imageDesktop}
                        onChange={(val) => onChange({ imageDesktop: val })}
                        aspectRatio="landscape"
                    />
                </div>

                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">Program Information</h3>
                    </div>

                    <div className="form-group">
                        <label className="form-label">Duration</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.meta.duration}
                            onChange={(e) => onChange({
                                meta: { ...data.meta, duration: e.target.value }
                            })}
                        />
                    </div>

                    <div className="sub-section">
                        <div className="sub-section-header">
                            <h4>Schedule</h4>
                            <button className="btn-mini-add" onClick={addScheduleItem}>
                                + Add Schedule
                            </button>
                        </div>
                        <div className="schedule-items">
                            {data.meta.schedule.map((item, index) => (
                                <div key={index} className="schedule-item">
                                    <div className="mini-item-row">
                                        <input
                                            type="text"
                                            className="form-input mini"
                                            value={item}
                                            onChange={(e) => updateScheduleItem(index, e.target.value)}
                                        />
                                        <button
                                            className="btn-mini-delete"
                                            onClick={() => removeScheduleItem(index)}
                                            title="Delete Schedule"
                                        >
                                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                <polyline points="3 6 5 6 21 6"></polyline>
                                                <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                            </svg>
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">Curriculum Content</h3>
                    </div>

                    <div className="curriculum-grid">
                        <div className="curriculum-column">
                            <div className="sub-section">
                                <div className="sub-section-header">
                                    <h4>Left Column</h4>
                                    <button className="btn-mini-add" onClick={() => addCurriculumItem('left')}>
                                        + Add Item
                                    </button>
                                </div>
                                <div className="curriculum-items">
                                    {data.curriculum.left.map((item, index) => (
                                        <div key={index} className="curriculum-item">
                                            <div className="mini-item-row">
                                                <input
                                                    type="text"
                                                    className="form-input mini"
                                                    value={item}
                                                    onChange={(e) => updateCurriculumItem('left', index, e.target.value)}
                                                />
                                                <button
                                                    className="btn-mini-delete"
                                                    onClick={() => removeCurriculumItem('left', index)}
                                                >
                                                    ×
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>

                        <div className="curriculum-column">
                            <div className="sub-section">
                                <div className="sub-section-header">
                                    <h4>Right Column</h4>
                                    <button className="btn-mini-add" onClick={() => addCurriculumItem('right')}>
                                        + Add Item
                                    </button>
                                </div>
                                <div className="curriculum-items">
                                    {data.curriculum.right.map((item, index) => (
                                        <div key={index} className="curriculum-item">
                                            <div className="mini-item-row">
                                                <input
                                                    type="text"
                                                    className="form-input mini"
                                                    value={item}
                                                    onChange={(e) => updateCurriculumItem('right', index, e.target.value)}
                                                />
                                                <button
                                                    className="btn-mini-delete"
                                                    onClick={() => removeCurriculumItem('right', index)}
                                                >
                                                    ×
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default ChuongTrinhCaoDangEditor