import React from 'react'
import './GhiDanhNhapHocEditor.css'
import { GhiDanhNhapHocContent, GhiDanhFieldText } from '../../contexts/CMSContext'
import ImageEditor from './ImageEditor'

type GhiDanhNhapHocEditorProps = {
    data: GhiDanhNhapHocContent
    onChange: (data: Partial<GhiDanhNhapHocContent>) => void
}

const GhiDanhNhapHocEditor: React.FC<GhiDanhNhapHocEditorProps> = ({ data, onChange }) => {

    const handleFieldChange = (fieldName: keyof GhiDanhNhapHocContent['fields'], subField: keyof GhiDanhFieldText, value: string) => {
        onChange({
            fields: {
                ...data.fields,
                [fieldName]: {
                    ...(data.fields[fieldName] as GhiDanhFieldText),
                    [subField]: value
                }
            }
        })
    }

    const handleGenderChange = (field: 'label' | 'male' | 'female', value: string) => {
        onChange({
            fields: {
                ...data.fields,
                gender: {
                    ...data.fields.gender,
                    [field]: value
                }
            }
        })
    }

    const handleSelectFieldChange = (fieldName: 'program' | 'attendance', field: 'label', value: string) => {
        onChange({
            fields: {
                ...data.fields,
                [fieldName]: {
                    ...data.fields[fieldName],
                    [field]: value
                }
            }
        })
    }

    const handleOptionChange = (fieldName: 'program' | 'attendance', index: number, value: string) => {
        const newOptions = [...data.fields[fieldName].options]
        newOptions[index] = { ...newOptions[index], label: value }
        onChange({
            fields: {
                ...data.fields,
                [fieldName]: {
                    ...data.fields[fieldName],
                    options: newOptions
                }
            }
        })
    }

    const addOption = (fieldName: 'program' | 'attendance') => {
        const newOptions = [...data.fields[fieldName].options, { id: `opt-${Date.now()}`, label: '' }]
        onChange({
            fields: {
                ...data.fields,
                [fieldName]: {
                    ...data.fields[fieldName],
                    options: newOptions
                }
            }
        })
    }

    const removeOption = (fieldName: 'program' | 'attendance', index: number) => {
        const newOptions = data.fields[fieldName].options.filter((_, i) => i !== index)
        onChange({
            fields: {
                ...data.fields,
                [fieldName]: {
                    ...data.fields[fieldName],
                    options: newOptions
                }
            }
        })
    }

    return (
        <div className="ghi-danh-editor">
            <div className="editor-header-title">
                <h2>Edit Ghi Danh Nhập Học</h2>
                <p className="editor-subtitle">Update registration form fields and section content</p>
            </div>

            <div className="editor-form">
                {/* General Content */}
                <div className="editor-section">
                    <div className="editor-section-title">General Information</div>
                    <div className="form-group">
                        <label className="form-label">Section Title</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.title}
                            onChange={(e) => onChange({ title: e.target.value })}
                        />
                    </div>
                    <ImageEditor
                        label="Desktop Featured Image"
                        hint="The large image shown on the left side of the form on desktop"
                        value={data.desktopImage}
                        onChange={(val) => onChange({ desktopImage: val })}
                        aspectRatio="portrait"
                    />
                    <div className="form-group">
                        <label className="form-label">Submit Button Label</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.submitLabel}
                            onChange={(e) => onChange({ submitLabel: e.target.value })}
                        />
                    </div>
                </div>

                {/* Form Fields */}
                <div className="editor-section">
                    <div className="editor-section-title">Form Fields Configuration</div>

                    <div className="field-grid">
                        {/* Full Name */}
                        <div className="form-group">
                            <label className="form-label">Full Name Field</label>
                            <div className="nested-fields">
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Label"
                                    value={data.fields.fullName.label}
                                    onChange={(e) => handleFieldChange('fullName', 'label', e.target.value)}
                                />
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Placeholder"
                                    value={data.fields.fullName.placeholder}
                                    onChange={(e) => handleFieldChange('fullName', 'placeholder', e.target.value)}
                                />
                            </div>
                        </div>

                        {/* Dharma Name */}
                        <div className="form-group">
                            <label className="form-label">Dharma Name Field</label>
                            <div className="nested-fields">
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Label"
                                    value={data.fields.dharmaName.label}
                                    onChange={(e) => handleFieldChange('dharmaName', 'label', e.target.value)}
                                />
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Placeholder"
                                    value={data.fields.dharmaName.placeholder}
                                    onChange={(e) => handleFieldChange('dharmaName', 'placeholder', e.target.value)}
                                />
                            </div>
                        </div>

                        {/* Birth Date */}
                        <div className="form-group">
                            <label className="form-label">Birth Date Field</label>
                            <div className="nested-fields">
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Label"
                                    value={data.fields.birthDate.label}
                                    onChange={(e) => handleFieldChange('birthDate', 'label', e.target.value)}
                                />
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Placeholder"
                                    value={data.fields.birthDate.placeholder}
                                    onChange={(e) => handleFieldChange('birthDate', 'placeholder', e.target.value)}
                                />
                            </div>
                        </div>

                        {/* Gender */}
                        <div className="form-group">
                            <label className="form-label">Gender Selection</label>
                            <div className="nested-fields">
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Main Label"
                                    value={data.fields.gender.label}
                                    onChange={(e) => handleGenderChange('label', e.target.value)}
                                />
                                <div style={{ display: 'flex', gap: '0.5rem' }}>
                                    <input
                                        type="text"
                                        className="form-input"
                                        placeholder="Male Label"
                                        value={data.fields.gender.male}
                                        onChange={(e) => handleGenderChange('male', e.target.value)}
                                    />
                                    <input
                                        type="text"
                                        className="form-input"
                                        placeholder="Female Label"
                                        value={data.fields.gender.female}
                                        onChange={(e) => handleGenderChange('female', e.target.value)}
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Email */}
                        <div className="form-group">
                            <label className="form-label">Email Field</label>
                            <div className="nested-fields">
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Label"
                                    value={data.fields.email.label}
                                    onChange={(e) => handleFieldChange('email', 'label', e.target.value)}
                                />
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Placeholder"
                                    value={data.fields.email.placeholder}
                                    onChange={(e) => handleFieldChange('email', 'placeholder', e.target.value)}
                                />
                            </div>
                        </div>

                        {/* Phone */}
                        <div className="form-group">
                            <label className="form-label">Phone Field</label>
                            <div className="nested-fields">
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Label"
                                    value={data.fields.phone.label}
                                    onChange={(e) => handleFieldChange('phone', 'label', e.target.value)}
                                />
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Placeholder"
                                    value={data.fields.phone.placeholder}
                                    onChange={(e) => handleFieldChange('phone', 'placeholder', e.target.value)}
                                />
                            </div>
                        </div>
                    </div>
                </div>

                {/* Select Options */}
                <div className="editor-section">
                    <div className="editor-section-title">Dropdown Fields Options</div>

                    <div className="field-grid">
                        {/* Programs */}
                        <div className="form-group">
                            <label className="form-label">Programs Dropdown Label</label>
                            <input
                                type="text"
                                className="form-input"
                                value={data.fields.program.label}
                                onChange={(e) => handleSelectFieldChange('program', 'label', e.target.value)}
                            />
                            <div className="options-list">
                                <label className="form-label" style={{ fontSize: '0.75rem', marginTop: '0.5rem' }}>Options</label>
                                {data.fields.program.options.map((option, index) => (
                                    <div key={option.id} className="option-item">
                                        <input
                                            type="text"
                                            className="form-input"
                                            value={option.label}
                                            onChange={(e) => handleOptionChange('program', index, e.target.value)}
                                        />
                                        <button className="btn-remove" onClick={() => removeOption('program', index)}>&times;</button>
                                    </div>
                                ))}
                                <button className="btn-add" onClick={() => addOption('program')}>+ Add Program Option</button>
                            </div>
                        </div>

                        {/* Attendance */}
                        <div className="form-group">
                            <label className="form-label">Attendance Dropdown Label</label>
                            <input
                                type="text"
                                className="form-input"
                                value={data.fields.attendance.label}
                                onChange={(e) => handleSelectFieldChange('attendance', 'label', e.target.value)}
                            />
                            <div className="options-list">
                                <label className="form-label" style={{ fontSize: '0.75rem', marginTop: '0.5rem' }}>Options</label>
                                {data.fields.attendance.options.map((option, index) => (
                                    <div key={option.id} className="option-item">
                                        <input
                                            type="text"
                                            className="form-input"
                                            value={option.label}
                                            onChange={(e) => handleOptionChange('attendance', index, e.target.value)}
                                        />
                                        <button className="btn-remove" onClick={() => removeOption('attendance', index)}>&times;</button>
                                    </div>
                                ))}
                                <button className="btn-add" onClick={() => addOption('attendance')}>+ Add Attendance Option</button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default GhiDanhNhapHocEditor
