type PageData = {
    name: string
    sections: Section[]
}

const stableStringify = (obj: any): string => {
    return JSON.stringify(obj, (_, value) => {
        if (value && typeof value === 'object' && !Array.isArray(value)) {
            return Object.keys(value).sort().reduce((sorted: any, key) => {
                sorted[key] = value[key];
                return sorted;
            }, {});
        }
        return value;
    });
};

