import React, { useState } from 'react'
import './CaoDangNienKhoaEditor.css'
import { Page5cCaoDangNienKhoaContent } from '../../contexts/CMSContext'
import ImageEditor from './ImageEditor'
import PopupDynamic from '../modals/PopupDynamic'

type CaoDangNienKhoaEditorProps = {
    data: Page5cCaoDangNienKhoaContent
    onChange: (data: Partial<Page5cCaoDangNienKhoaContent>) => void
}

const CaoDangNienKhoaEditor: React.FC<CaoDangNienKhoaEditorProps> = ({ data, onChange }) => {
    const [editingBlockId, setEditingBlockId] = useState<string | null>(null)
    const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null)

    const updateBlock = (blockId: string, updates: any) => {
        const updatedBlocks = data.blocks.map(block =>
            block.id === blockId ? { ...block, ...updates } : block
        )
        onChange({ blocks: updatedBlocks })
    }

    const addBlock = () => {
        const newBlock = {
            id: `cd-nk-block-${Date.now()}`,
            type: 'course' as const,
            title: 'New Block',
            imageDesktop: '',
            courses: []
        }
        onChange({ blocks: [...data.blocks, newBlock] as any })
        setEditingBlockId(newBlock.id)
    }

    const removeBlock = (blockId: string) => {
        const updatedBlocks = data.blocks.filter(block => block.id !== blockId)
        onChange({ blocks: updatedBlocks })
    }

    const addScheduleItem = (blockId: string) => {
        const block = data.blocks.find(b => b.id === blockId)
        if (block && block.type === 'schedule') {
            const newItem = {
                id: `day-${Date.now()}`,
                dayLabel: 'New Day',
                details: ['New schedule item']
            }
            updateBlock(blockId, {
                schedules: {
                    ...block.schedules,
                    items: [...block.schedules.items, newItem]
                }
            })
        }
    }

    const removeScheduleItem = (blockId: string, itemId: string) => {
        const block = data.blocks.find(b => b.id === blockId)
        if (block && block.type === 'schedule') {
            const updatedItems = block.schedules.items.filter(item => item.id !== itemId)
            updateBlock(blockId, {
                schedules: {
                    ...block.schedules,
                    items: updatedItems
                }
            })
        }
    }

    const removeScheduleDetail = (blockId: string, itemIndex: number, detailIndex: number) => {
        const block = data.blocks.find(b => b.id === blockId)
        if (block && block.type === 'schedule') {
            const updatedItems = [...block.schedules.items]
            const updatedDetails = updatedItems[itemIndex].details.filter((_, i) => i !== detailIndex)
            updatedItems[itemIndex] = { ...updatedItems[itemIndex], details: updatedDetails }
            updateBlock(blockId, {
                schedules: { ...block.schedules, items: updatedItems }
            })
        }
    }

    const addScheduleDetail = (blockId: string, itemIndex: number) => {
        const block = data.blocks.find(b => b.id === blockId)
        if (block && block.type === 'schedule') {
            const updatedItems = [...block.schedules.items]
            updatedItems[itemIndex] = {
                ...updatedItems[itemIndex],
                details: [...updatedItems[itemIndex].details, 'New schedule item']
            }
            updateBlock(blockId, {
                schedules: { ...block.schedules, items: updatedItems }
            })
        }
    }

    const addCourse = (blockId: string) => {
        const block = data.blocks.find(b => b.id === blockId)
        if (block && block.type === 'course') {
            const newCourse = {
                id: `c-${Date.now()}`,
                title: 'New Course Title',
                description: 'Course description...'
            }
            updateBlock(blockId, {
                courses: [...block.courses, newCourse]
            })
        }
    }

    const removeCourse = (blockId: string, courseId: string) => {
        const block = data.blocks.find(b => b.id === blockId)
        if (block && block.type === 'course') {
            const updatedCourses = block.courses.filter(c => c.id !== courseId)
            updateBlock(blockId, { courses: updatedCourses })
        }
    }

    const updateCourse = (blockId: string, courseId: string, updates: any) => {
        const block = data.blocks.find(b => b.id === blockId)
        if (block && block.type === 'course') {
            const updatedCourses = block.courses.map(c =>
                c.id === courseId ? { ...c, ...updates } : c
            )
            updateBlock(blockId, { courses: updatedCourses })
        }
    }

    return (
        <div className="cao-dang-nien-khoa-editor">
            <div className="editor-header-title">
                <h2>Edit Cao Đẳng Niên Khóa Content</h2>
                <p className="editor-subtitle">Manage schedule and course blocks</p>
            </div>

            <div className="editor-form">
                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">Cao Đẳng Blocks</h3>
                        <button className="btn-add-item" onClick={addBlock}>
                            + Add Block
                        </button>
                    </div>

                    <div className="blocks-list">
                        {data.blocks.map((block) => (
                            <div key={block.id} className={`block-card ${editingBlockId === block.id ? 'active' : ''}`}>
                                <div className="block-card-header">
                                    <div className="block-info">
                                        <span className="block-type-badge">{block.type}</span>
                                        <span className="item-label">{block.title}</span>
                                    </div>
                                    <div className="item-actions">
                                        <button
                                            className="btn-action edit"
                                            onClick={() => setEditingBlockId(editingBlockId === block.id ? null : block.id)}
                                        >
                                            {editingBlockId === block.id ? 'Close' : 'Edit'}
                                        </button>
                                        <button
                                            className="btn-action delete"
                                            onClick={() => setDeleteConfirmId(block.id)}
                                        >
                                            Delete
                                        </button>
                                    </div>
                                </div>

                                {editingBlockId === block.id && (
                                    <div className="block-item-editor">
                                        <div className="form-group">
                                            <label className="form-label">Block Title</label>
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={block.title}
                                                onChange={(e) => updateBlock(block.id, { title: e.target.value })}
                                            />
                                        </div>

                                        {block.imageDesktop && (
                                            <ImageEditor
                                                label="Desktop Image"
                                                value={block.imageDesktop}
                                                onChange={(val) => updateBlock(block.id, { imageDesktop: val })}
                                                aspectRatio="landscape"
                                            />
                                        )}

                                        {(block as any).imageMobile && (
                                            <ImageEditor
                                                label="Mobile Image"
                                                value={(block as any).imageMobile}
                                                onChange={(val) => updateBlock(block.id, { imageMobile: val })}
                                                aspectRatio="portrait"
                                            />
                                        )}

                                        {block.type === 'schedule' && (
                                            <div className="sub-section">
                                                <div className="sub-section-header">
                                                    <h4>Schedule Settings</h4>
                                                </div>
                                                <div className="form-group">
                                                    <label className="form-label">Schedule Heading</label>
                                                    <input
                                                        type="text"
                                                        className="form-input"
                                                        value={block.schedules.heading}
                                                        onChange={(e) => updateBlock(block.id, {
                                                            schedules: { ...block.schedules, heading: e.target.value }
                                                        })}
                                                    />
                                                </div>
                                                <div className="sub-section-header">
                                                    <h4>Schedule Items</h4>
                                                    <div className="sub-section-actions">
                                                        <button className="btn-mini-add" onClick={() => addScheduleItem(block.id)}>
                                                            + Add Schedule
                                                        </button>
                                                    </div>
                                                </div>
                                                {block.schedules.items.map((item, itemIndex) => (
                                                    <div key={item.id} className="schedule-edit-card">
                                                        <div className="mini-item-row" style={{ alignItems: 'center' }}>
                                                            <input
                                                                type="text"
                                                                className="form-input mini"
                                                                placeholder="Day Label"
                                                                value={item.dayLabel}
                                                                onChange={(e) => {
                                                                    const updatedItems = [...block.schedules.items]
                                                                    updatedItems[itemIndex] = { ...item, dayLabel: e.target.value }
                                                                    updateBlock(block.id, {
                                                                        schedules: { ...block.schedules, items: updatedItems }
                                                                    })
                                                                }}
                                                            />
                                                            <div className="sub-section-actions">
                                                                <button
                                                                    className="btn-mini-add"
                                                                    onClick={() => addScheduleDetail(block.id, itemIndex)}
                                                                >
                                                                    + Add Detail
                                                                </button>
                                                                <button
                                                                    className="btn-mini-delete"
                                                                    onClick={() => removeScheduleItem(block.id, item.id)}
                                                                    title="Delete Schedule"
                                                                >
                                                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                                        <polyline points="3 6 5 6 21 6"></polyline>
                                                                        <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                                                    </svg>
                                                                </button>
                                                            </div>
                                                        </div>
                                                        <div className="schedule-details">
                                                            <h5 style={{ fontSize: '0.75rem', color: '#6b7280', marginBottom: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                                                                Details
                                                            </h5>
                                                        </div>
                                                        {item.details.map((detail, detailIndex) => (
                                                            <div key={detailIndex} className="mini-item-row">
                                                                <input
                                                                    type="text"
                                                                    className="form-input mini"
                                                                    value={detail}
                                                                    onChange={(e) => {
                                                                        const updatedItems = [...block.schedules.items]
                                                                        const updatedDetails = [...item.details]
                                                                        updatedDetails[detailIndex] = e.target.value
                                                                        updatedItems[itemIndex] = { ...item, details: updatedDetails }
                                                                        updateBlock(block.id, {
                                                                            schedules: { ...block.schedules, items: updatedItems }
                                                                        })
                                                                    }}
                                                                />
                                                                <button
                                                                    className="btn-mini-delete"
                                                                    onClick={() => removeScheduleDetail(block.id, itemIndex, detailIndex)}
                                                                    title="Delete Detail"
                                                                >
                                                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                                        <polyline points="3 6 5 6 21 6"></polyline>
                                                                        <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                                                    </svg>
                                                                </button>
                                                            </div>
                                                        ))}
                                                    </div>
                                                ))}
                                            </div>
                                        )}

                                        {block.type === 'course' && (
                                            <div className="sub-section">
                                                <div className="sub-section-header">
                                                    <h4>Courses</h4>
                                                    <button className="btn-mini-add" onClick={() => addCourse(block.id)}>
                                                        + Add Course
                                                    </button>
                                                </div>
                                                <div className="courses-editor-list">
                                                    {block.courses.map((course) => (
                                                        <div key={course.id} className="course-edit-card">
                                                            <div className="mini-item-row">
                                                                <input
                                                                    type="text"
                                                                    className="form-input mini"
                                                                    placeholder="Course Title"
                                                                    value={course.title}
                                                                    onChange={(e) => updateCourse(block.id, course.id, { title: e.target.value })}
                                                                />
                                                                <button
                                                                    className="btn-mini-delete"
                                                                    onClick={() => removeCourse(block.id, course.id)}
                                                                    title="Delete Course"
                                                                >
                                                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                                        <polyline points="3 6 5 6 21 6"></polyline>
                                                                        <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                                                    </svg>
                                                                </button>
                                                            </div>
                                                            <textarea
                                                                className="form-input"
                                                                rows={3}
                                                                placeholder="Course Description"
                                                                value={course.description}
                                                                onChange={(e) => updateCourse(block.id, course.id, { description: e.target.value })}
                                                            />
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            <PopupDynamic
                isOpen={!!deleteConfirmId}
                onClose={() => setDeleteConfirmId(null)}
                title="Delete Block?"
                subtitle={`Are you sure you want to delete the block "${data.blocks.find(b => b.id === deleteConfirmId)?.title}"? This will remove all its content permanently.`}
                type="error"
                buttons={[
                    {
                        buttonText: "Yes, Delete Block",
                        buttonTextActive: "Deleting...",
                        buttonTextResponse: "Deleted!",
                        variant: "danger",
                        onClick: async () => {
                            if (deleteConfirmId) {
                                removeBlock(deleteConfirmId);
                                setDeleteConfirmId(null);
                            }
                        }
                    },
                    {
                        buttonText: "Cancel",
                        variant: "secondary",
                        onClick: () => setDeleteConfirmId(null)
                    }
                ]}
            />
        </div>
    )
}

export default CaoDangNienKhoaEditor