import React from 'react'
import './ChuyenKhoaATyDamEditor.css'
import { Page6aChuyenKhoaATyDamContent } from '../../contexts/CMSContext'
import ImageEditor from './ImageEditor'

type ChuyenKhoaATyDamEditorProps = {
    data: Page6aChuyenKhoaATyDamContent
    onChange: (data: Partial<Page6aChuyenKhoaATyDamContent>) => void
}

const ChuyenKhoaATyDamEditor: React.FC<ChuyenKhoaATyDamEditorProps> = ({ data, onChange }) => {

    const updateScheduleItem = (index: number, value: string) => {
        const newSchedule = [...data.meta.schedule]
        newSchedule[index] = value
        onChange({
            meta: {
                ...data.meta,
                schedule: newSchedule
            }
        })
    }

    const addScheduleItem = () => {
        onChange({
            meta: {
                ...data.meta,
                schedule: [...data.meta.schedule, 'New schedule item']
            }
        })
    }

    const removeScheduleItem = (index: number) => {
        if (!window.confirm('Delete this schedule?')) return
        const newSchedule = data.meta.schedule.filter((_, i) => i !== index)
        onChange({
            meta: {
                ...data.meta,
                schedule: newSchedule
            }
        })
    }

    const updateCurriculumItem = (section: 'kosa' | 'abhidhamma', index: number, value: string) => {
        const newItems = [...data.curriculum[section].items]
        newItems[index] = value
        onChange({
            curriculum: {
                ...data.curriculum,
                [section]: {
                    ...data.curriculum[section],
                    items: newItems
                }
            }
        })
    }

    const addCurriculumItem = (section: 'kosa' | 'abhidhamma') => {
        const newItems = [...data.curriculum[section].items, 'New curriculum item']
        onChange({
            curriculum: {
                ...data.curriculum,
                [section]: {
                    ...data.curriculum[section],
                    items: newItems
                }
            }
        })
    }

    const removeCurriculumItem = (section: 'kosa' | 'abhidhamma', index: number) => {
        const newItems = data.curriculum[section].items.filter((_, i) => i !== index)
        onChange({
            curriculum: {
                ...data.curriculum,
                [section]: {
                    ...data.curriculum[section],
                    items: newItems
                }
            }
        })
    }

    return (
        <div className="chuyen-khoa-a-ty-dam-editor">
            <div className="editor-header-title">
                <h2>Edit Chuyên Khoa A Tỳ Đàm</h2>
                <p className="editor-subtitle">Manage program details and specialized curriculum</p>
            </div>

            <div className="editor-form">
                <div className="form-section">
                    <div className="form-group">
                        <label className="form-label">Program Title</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.title}
                            onChange={(e) => onChange({ title: e.target.value })}
                        />
                    </div>

                    <ImageEditor
                        label="Program Image"
                        value={data.image.src}
                        onChange={(val) => onChange({
                            image: { ...data.image, src: val }
                        })}
                        aspectRatio="landscape"
                    />

                    <div className="form-group">
                        <label className="form-label">Image Alt Text</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.image.alt}
                            onChange={(e) => onChange({
                                image: { ...data.image, alt: e.target.value }
                            })}
                        />
                    </div>
                </div>

                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">Program Information</h3>
                    </div>

                    <div className="form-group">
                        <label className="form-label">Duration</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.meta.duration}
                            onChange={(e) => onChange({
                                meta: { ...data.meta, duration: e.target.value }
                            })}
                        />
                    </div>

                    <div className="sub-section">
                        <div className="sub-section-header">
                            <h4>Schedule</h4>
                            <button className="btn-mini-add" onClick={addScheduleItem}>
                                + Add Schedule
                            </button>
                        </div>
                        <div className="schedule-items">
                            {data.meta.schedule.map((item, index) => (
                                <div key={index} className="schedule-item">
                                    <div className="mini-item-row">
                                        <input
                                            type="text"
                                            className="form-input mini"
                                            value={item}
                                            onChange={(e) => updateScheduleItem(index, e.target.value)}
                                        />
                                        <button
                                            className="btn-mini-delete"
                                            onClick={() => removeScheduleItem(index)}
                                            title="Delete Schedule"
                                        >
                                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                <polyline points="3 6 5 6 21 6"></polyline>
                                                <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                            </svg>
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">Curriculum Content</h3>
                    </div>

                    <div className="curriculum-grid">
                        <div className="curriculum-column">
                            <div className="sub-section">
                                <div className="sub-section-header">
                                    <h4>Tạng Câu Xá Luận</h4>
                                    <button className="btn-mini-add" onClick={() => addCurriculumItem('kosa')}>
                                        + Add Item
                                    </button>
                                </div>
                                <div className="form-group">
                                    <label className="form-label">Section Heading</label>
                                    <input
                                        type="text"
                                        className="form-input"
                                        value={data.curriculum.kosa.heading}
                                        onChange={(e) => onChange({
                                            curriculum: {
                                                ...data.curriculum,
                                                kosa: {
                                                    ...data.curriculum.kosa,
                                                    heading: e.target.value
                                                }
                                            }
                                        })}
                                    />
                                </div>
                                <div className="curriculum-items">
                                    {data.curriculum.kosa.items.map((item, index) => (
                                        <div key={index} className="curriculum-item">
                                            <div className="mini-item-row">
                                                <input
                                                    type="text"
                                                    className="form-input mini"
                                                    value={item}
                                                    onChange={(e) => updateCurriculumItem('kosa', index, e.target.value)}
                                                />
                                                <button
                                                    className="btn-mini-delete"
                                                    onClick={() => removeCurriculumItem('kosa', index)}
                                                >
                                                    ×
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>

                        <div className="curriculum-column">
                            <div className="sub-section">
                                <div className="sub-section-header">
                                    <h4>Tạng Vi Diệu Pháp</h4>
                                    <button className="btn-mini-add" onClick={() => addCurriculumItem('abhidhamma')}>
                                        + Add Item
                                    </button>
                                </div>
                                <div className="form-group">
                                    <label className="form-label">Section Heading</label>
                                    <input
                                        type="text"
                                        className="form-input"
                                        value={data.curriculum.abhidhamma.heading}
                                        onChange={(e) => onChange({
                                            curriculum: {
                                                ...data.curriculum,
                                                abhidhamma: {
                                                    ...data.curriculum.abhidhamma,
                                                    heading: e.target.value
                                                }
                                            }
                                        })}
                                    />
                                </div>
                                <div className="curriculum-items">
                                    {data.curriculum.abhidhamma.items.map((item, index) => (
                                        <div key={index} className="curriculum-item">
                                            <div className="mini-item-row">
                                                <input
                                                    type="text"
                                                    className="form-input mini"
                                                    value={item}
                                                    onChange={(e) => updateCurriculumItem('abhidhamma', index, e.target.value)}
                                                />
                                                <button
                                                    className="btn-mini-delete"
                                                    onClick={() => removeCurriculumItem('abhidhamma', index)}
                                                >
                                                    ×
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default ChuyenKhoaATyDamEditor