import React from 'react'
import './ChuyenKhoaATyDamEditor.css'
import { ProgramSectionEFContent } from '../../contexts/CMSContext'
import ImageEditor from './ImageEditor'

type ProgramSectionEFEditorProps = {
    data: ProgramSectionEFContent
    onChange: (data: Partial<ProgramSectionEFContent>) => void
}

const ProgramSectionEFEditor: React.FC<ProgramSectionEFEditorProps> = ({ data, onChange }) => {

    const updateLink = (index: number, field: string, value: string) => {
        const newLinks = [...data.links]
        newLinks[index] = { ...newLinks[index], [field]: value }
        onChange({ links: newLinks })
    }

    const addLink = () => {
        const newLink = {
            id: `ef-${Date.now()}`,
            label: 'New Link',
            href: '#'
        }
        onChange({ links: [...data.links, newLink] })
    }

    const removeLink = (index: number) => {
        if (!window.confirm('Delete this link?')) return
        const newLinks = data.links.filter((_, i) => i !== index)
        onChange({ links: newLinks })
    }

    return (
        <div className="chuyen-khoa-a-ty-dam-editor">
            <div className="editor-header-title">
                <h2>Edit Program Section EF</h2>
                <p className="editor-subtitle">Manage program section content and links</p>
            </div>

            <div className="editor-form">
                <div className="form-section">
                    <div className="form-group">
                        <label className="form-label">Section Title</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.title}
                            onChange={(e) => onChange({ title: e.target.value })}
                        />
                    </div>

                    <ImageEditor
                        label="Desktop Image"
                        value={data.images.desktop}
                        onChange={(val) => onChange({
                            images: { ...data.images, desktop: val }
                        })}
                        aspectRatio="landscape"
                    />

                    <ImageEditor
                        label="Mobile Image"
                        value={data.images.mobile}
                        onChange={(val) => onChange({
                            images: { ...data.images, mobile: val }
                        })}
                        aspectRatio="landscape"
                    />

                    <div className="form-group">
                        <label className="form-label">Image Alt Text</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.images.alt}
                            onChange={(e) => onChange({
                                images: { ...data.images, alt: e.target.value }
                            })}
                        />
                    </div>
                </div>

                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">Program Links</h3>
                    </div>

                    <div className="sub-section">
                        <div className="sub-section-header">
                            <h4>Links</h4>
                            <button className="btn-mini-add" onClick={addLink}>
                                + Add Link
                            </button>
                        </div>
                        <div className="schedule-items">
                            {data.links.map((link, index) => (
                                <div key={link.id} className="schedule-item">
                                    <div className="mini-item-row">
                                        <input
                                            type="text"
                                            className="form-input mini"
                                            placeholder="Link Label"
                                            value={link.label}
                                            onChange={(e) => updateLink(index, 'label', e.target.value)}
                                        />
                                        <input
                                            type="text"
                                            className="form-input mini"
                                            placeholder="Link URL"
                                            value={link.href}
                                            onChange={(e) => updateLink(index, 'href', e.target.value)}
                                        />
                                        <button
                                            className="btn-mini-delete"
                                            onClick={() => removeLink(index)}
                                            title="Delete Link"
                                        >
                                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                <polyline points="3 6 5 6 21 6"></polyline>
                                                <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                            </svg>
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default ProgramSectionEFEditor