import React, { useState } from 'react'
import './HeaderContentEditor.css'
import { HeaderContent, NavItem } from '../../contexts/CMSContext'
import ImageEditor from './ImageEditor'

type HeaderContentEditorProps = {
    data: HeaderContent
    onChange: (data: Partial<HeaderContent>) => void
}

const HeaderContentEditor: React.FC<HeaderContentEditorProps> = ({ data, onChange }) => {
    const [editingNavId, setEditingNavId] = useState<string | null>(null)

    const updateNavItem = (id: string, updates: Partial<NavItem>) => {
        const updatedItems = data.navigationItems.map(item =>
            item.id === id ? { ...item, ...updates } : item
        )
        onChange({ navigationItems: updatedItems })
    }

    const addDropdownItem = (navId: string) => {
        const navItem = data.navigationItems.find(item => item.id === navId)
        if (!navItem || !navItem.isDropdown) return

        const newDropdownItem = {
            id: `dropdown-${Date.now()}`,
            label: 'New Item',
            href: '#'
        }

        const updatedItems = data.navigationItems.map(item =>
            item.id === navId
                ? { ...item, dropdownItems: [...(item.dropdownItems || []), newDropdownItem] }
                : item
        )
        onChange({ navigationItems: updatedItems })
    }

    const updateDropdownItem = (navId: string, dropdownId: string, updates: Partial<{ label: string; href: string }>) => {
        const updatedItems = data.navigationItems.map(item =>
            item.id === navId && item.dropdownItems
                ? {
                    ...item,
                    dropdownItems: item.dropdownItems.map(dropItem =>
                        dropItem.id === dropdownId ? { ...dropItem, ...updates } : dropItem
                    )
                }
                : item
        )
        onChange({ navigationItems: updatedItems })
    }

    const removeDropdownItem = (navId: string, dropdownId: string) => {
        const updatedItems = data.navigationItems.map(item =>
            item.id === navId && item.dropdownItems
                ? {
                    ...item,
                    dropdownItems: item.dropdownItems.filter(dropItem => dropItem.id !== dropdownId)
                }
                : item
        )
        onChange({ navigationItems: updatedItems })
    }

    return (
        <div className="header-content-editor">
            <div className="editor-header-title">
                <h2>Edit Header Content</h2>
                <p className="editor-subtitle">Manage logo and navigation links</p>
            </div>

            <div className="editor-form">
                {/* Logo Section using Reusable Component */}
                <div className="form-section">
                    <h3 className="section-title">Logo Settings</h3>

                    <ImageEditor
                        label="Logo Image"
                        hint="Site logo shown in header"
                        value={data.logoImage}
                        onChange={(val) => onChange({ logoImage: val })}
                        aspectRatio="logo"
                        placeholder="Paste logo URL here..."
                    />

                    <div className="form-group">
                        <label htmlFor="logo-vietnamese" className="form-label">
                            Vietnamese Text
                        </label>
                        <input
                            id="logo-vietnamese"
                            type="text"
                            className="form-input"
                            value={data.logoVietnamese}
                            onChange={(e) => onChange({ logoVietnamese: e.target.value })}
                            placeholder="VIỆN PHẬT HỌC"
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="logo-english" className="form-label">
                            English Text
                        </label>
                        <input
                            id="logo-english"
                            type="text"
                            className="form-input"
                            value={data.logoEnglish}
                            onChange={(e) => onChange({ logoEnglish: e.target.value })}
                            placeholder="Sakya Buddha University"
                        />
                    </div>
                </div>

                {/* Navigation Items Section */}
                <div className="form-section">
                    <h3 className="section-title">Navigation Items</h3>

                    <div className="nav-items-list">
                        {data.navigationItems.map((navItem, index) => (
                            <div key={navItem.id} className="nav-item-card">
                                <div className="nav-item-header">
                                    <span className="nav-item-number">{index + 1}</span>
                                    <h4 className="nav-item-title">{navItem.label}</h4>
                                    <button
                                        className="toggle-edit-btn"
                                        onClick={() => setEditingNavId(editingNavId === navItem.id ? null : navItem.id)}
                                    >
                                        {editingNavId === navItem.id ? 'Close' : 'Edit'}
                                    </button>
                                </div>

                                {editingNavId === navItem.id && (
                                    <div className="nav-item-editor">
                                        <div className="form-group">
                                            <label className="form-label">Label</label>
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={navItem.label}
                                                onChange={(e) => updateNavItem(navItem.id, { label: e.target.value })}
                                                placeholder="Menu label"
                                            />
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label">Link URL</label>
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={navItem.href}
                                                onChange={(e) => updateNavItem(navItem.id, { href: e.target.value })}
                                                placeholder="/page-url"
                                                disabled={navItem.isDropdown}
                                            />
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label toggle-label">
                                                <span>Is Dropdown Menu</span>
                                                <div className="toggle-wrapper">
                                                    <input
                                                        type="checkbox"
                                                        className="toggle-checkbox"
                                                        checked={navItem.isDropdown}
                                                        onChange={(e) => updateNavItem(navItem.id, {
                                                            isDropdown: e.target.checked,
                                                            dropdownItems: e.target.checked ? (navItem.dropdownItems || []) : undefined
                                                        })}
                                                    />
                                                    <span className="toggle-slider"></span>
                                                </div>
                                            </label>
                                        </div>

                                        {navItem.isDropdown && (
                                            <div className="dropdown-items-section">
                                                <div className="dropdown-header">
                                                    <h5>Dropdown Items</h5>
                                                    <button
                                                        className="add-dropdown-btn"
                                                        onClick={() => addDropdownItem(navItem.id)}
                                                    >
                                                        + Add Item
                                                    </button>
                                                </div>

                                                {navItem.dropdownItems?.map((dropItem) => (
                                                    <div key={dropItem.id} className="dropdown-item-card">
                                                        <div className="dropdown-item-fields">
                                                            <input
                                                                type="text"
                                                                className="form-input small"
                                                                value={dropItem.label}
                                                                onChange={(e) => updateDropdownItem(navItem.id, dropItem.id, { label: e.target.value })}
                                                                placeholder="Item label"
                                                            />
                                                            <input
                                                                type="text"
                                                                className="form-input small"
                                                                value={dropItem.href}
                                                                onChange={(e) => updateDropdownItem(navItem.id, dropItem.id, { href: e.target.value })}
                                                                placeholder="Item URL"
                                                            />
                                                            <button
                                                                className="remove-btn"
                                                                onClick={() => removeDropdownItem(navItem.id, dropItem.id)}
                                                                title="Remove item"
                                                            >
                                                                ×
                                                            </button>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    )
}

export default HeaderContentEditor
