import React, { useState } from 'react'
import './SupportEditor.css'
import { SupportContent, SupportColumn, SupportItem } from '../../contexts/CMSContext'
import ImageEditor from './ImageEditor'

type SupportEditorProps = {
    data: SupportContent
    onChange: (data: Partial<SupportContent>) => void
}

const SupportEditor: React.FC<SupportEditorProps> = ({ data, onChange }) => {
    const [editingColumnId, setEditingColumnId] = useState<string | null>(null)

    const updateColumn = (colId: string, updates: Partial<SupportColumn>) => {
        const updatedColumns = data.columns.map(col =>
            col.id === colId ? { ...col, ...updates } : col
        )
        onChange({ columns: updatedColumns })
    }

    const updateItem = (colId: string, itemId: string, updates: Partial<SupportItem>) => {
        const column = data.columns.find(c => c.id === colId)
        if (!column) return

        const updatedItems = column.items.map(item =>
            item.id === itemId ? { ...item, ...updates } : item
        )
        updateColumn(colId, { items: updatedItems })
    }

    const addItem = (colId: string) => {
        const column = data.columns.find(c => c.id === colId)
        if (!column) return

        const newItem: SupportItem = {
            id: `item-${Date.now()}`,
            title: 'New Title',
            image: ''
        }
        updateColumn(colId, { items: [...column.items, newItem] })
    }

    const removeItem = (colId: string, itemId: string) => {
        const column = data.columns.find(c => c.id === colId)
        if (!column) return

        const updatedItems = column.items.filter(item => item.id !== itemId)
        updateColumn(colId, { items: updatedItems })
    }

    return (
        <div className="support-editor">
            <div className="editor-header-title">
                <h2>Edit Dharma Support</h2>
                <p className="editor-subtitle">Manage columns and items for the support section</p>
            </div>

            <div className="editor-form">
                <div className="form-group">
                    <label className="form-label">Section Main Title</label>
                    <textarea
                        className="form-input"
                        rows={2}
                        value={data.sectionTitle}
                        onChange={(e) => onChange({ sectionTitle: e.target.value })}
                        placeholder="Use \n for line breaks"
                    />
                </div>

                <div className="form-grid-2">
                    <ImageEditor
                        label="Desktop Background"
                        value={data.backgroundImage}
                        onChange={(url) => onChange({ backgroundImage: url })}
                        aspectRatio="landscape"
                    />
                    <ImageEditor
                        label="Mobile Background"
                        value={data.mobileBackgroundImage}
                        onChange={(url) => onChange({ mobileBackgroundImage: url })}
                        aspectRatio="landscape"
                    />
                </div>

                <div className="columns-list">
                    {data.columns.map((column) => (
                        <div key={column.id} className={`column-card ${editingColumnId === column.id ? 'active' : ''}`}>
                            <div className="column-card-header">
                                <span className="item-label">{column.title || 'Untitled Column'}</span>
                                <button
                                    className="btn-action edit"
                                    onClick={() => setEditingColumnId(editingColumnId === column.id ? null : column.id)}
                                >
                                    {editingColumnId === column.id ? 'Close' : 'Edit'}
                                </button>
                            </div>

                            {editingColumnId === column.id && (
                                <div className="column-item-editor">
                                    <div className="form-group">
                                        <label className="form-label">Column Title</label>
                                        <input
                                            type="text"
                                            className="form-input"
                                            value={column.title}
                                            onChange={(e) => updateColumn(column.id, { title: e.target.value })}
                                        />
                                    </div>

                                    <div className="items-section">
                                        <div className="sub-section-header">
                                            <h4>Column Items</h4>
                                            <button className="btn-mini-add" onClick={() => addItem(column.id)}>+ Add Item</button>
                                        </div>

                                        <div className="items-grid-editor">
                                            {column.items.map((item) => (
                                                <div key={item.id} className="item-edit-card">
                                                    <ImageEditor
                                                        label="Thumbnail"
                                                        value={item.image}
                                                        onChange={(url) => updateItem(column.id, item.id, { image: url })}
                                                        aspectRatio="square"
                                                        compact={true}
                                                    />
                                                    <div className="item-edit-details">
                                                        <input
                                                            type="text"
                                                            className="form-input mini"
                                                            placeholder="Item title"
                                                            value={item.title}
                                                            onChange={(e) => updateItem(column.id, item.id, { title: e.target.value })}
                                                        />
                                                        <button className="btn-mini-delete" onClick={() => removeItem(column.id, item.id)} title="Delete Item">
                                                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                                <polyline points="3 6 5 6 21 6"></polyline>
                                                                <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                                            </svg>
                                                        </button>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>
        </div>
    )
}

export default SupportEditor
